INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cf6f88d1-560f-5775-bd45-770691d8d254', '17c9aa2f-c0a8-5656-a919-e51b88b6bc86', 'كان مع أحمد 845 مليمًا، فاشترى لعبةً بـ 367 مليمًا. كم بقي معه؟', '[{"id":"a","text":"522 مليمًا"},{"id":"b","text":"588 مليمًا"},{"id":"c","text":"478 مليمًا"},{"id":"d","text":"1 212 مليمًا"}]'::jsonb, 'c', 'نطرح لأنّه صرف من ماله: 845 − 367. الآحاد 5 أصغر من 7، نستلف؛ 15 − 7 = 8. العشرات صارت 3، نستلف؛ 13 − 6 = 7. المئات صارت 7؛ 7 − 3 = 4. ✓ بقي 478 مليمًا. الفخّ: جمع المبلغين بدل طرحهما.', 1)
