  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('544b1021-4f98-5fea-84af-023ebd9c0967', '17c9aa2f-c0a8-5656-a919-e51b88b6bc86', 'ما نتيجة الجمع 1 736 + 2 589؟', '[{"id":"a","text":"4 215"},{"id":"b","text":"4 325"},{"id":"c","text":"3 325"},{"id":"d","text":"4 225"}]'::jsonb, 'b', 'الآحاد: 6 + 9 = 15 (نكتب 5 نحتفظ 1). العشرات: 3 + 8 + 1 = 12 (نكتب 2 نحتفظ 1). المئات: 7 + 5 + 1 = 13 (نكتب 3 نحتفظ 1). الآلاف: 1 + 2 + 1 = 4. ✓ المجموع 4 325. الفخّ: نسيان احتفاظٍ في سلسلة الاحتفاظات.', 2)
