  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('69784f79-133b-5ccb-b41d-1fdd28a43738', '17c9aa2f-c0a8-5656-a919-e51b88b6bc86', 'ما نتيجة الطرح 3 000 − 1 426؟', '[{"id":"a","text":"1 684"},{"id":"b","text":"2 426"},{"id":"c","text":"1 674"},{"id":"d","text":"1 574"}]'::jsonb, 'd', 'نستلف عبر الأصفار: الآحاد 0 → 10 − 6 = 4. العشرات صارت 9 − 2 = 7. المئات صارت 9 − 4 = 5. الآلاف صارت 2 − 1 = 1. ✓ الفرق 1 574. التحقّق: 1 574 + 1 426 = 3 000 ✓. الفخّ: الاستلاف عبر ثلاثة أصفار متتالية.', 3)
