INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3b20522b-a506-5f11-8286-56e03054bcaa', '17c9aa2f-c0a8-5656-a919-e51b88b6bc86', 'ما الحدّ المجهول في العمليّة ? + 1 250 = 3 000؟', '[{"id":"a","text":"1 750"},{"id":"b","text":"2 250"},{"id":"c","text":"1 850"},{"id":"d","text":"4 250"}]'::jsonb, 'a', 'لإيجاد الحدّ المجهول نطرح الحدّ المعلوم من المجموع: ? = 3 000 − 1 250 = 1 750. ✓ التحقّق: 1 750 + 1 250 = 3 000 ✓. الفخّ: جمع 3 000 + 1 250 بدل طرحهما.', 4)
