  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e943312f-f6a2-5058-971b-52dcefe73805', '17c9aa2f-c0a8-5656-a919-e51b88b6bc86', 'جمع قسمٌ 1 245 دينارًا للجمعيّة، وجمع قسمٌ آخر 968 دينارًا. كم جمع القسمان معًا؟', '[{"id":"a","text":"2 113 دينارًا"},{"id":"b","text":"2 103 دنانير"},{"id":"c","text":"2 213 دينارًا"},{"id":"d","text":"2 223 دينارًا"}]'::jsonb, 'c', 'نجمع المبلغين: 1 245 + 968. الآحاد 5 + 8 = 13 (نحتفظ 1). العشرات 4 + 6 + 1 = 11 (نحتفظ 1). المئات 2 + 9 + 1 = 12 (نحتفظ 1). الآلاف 1 + 0 + 1 = 2. ✓ المجموع 2 213 دينارًا. الفخّ: نسيان احتفاظ المئات.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fc5db26c-b5d2-58ad-b798-789fa54a0e5c', '17c9aa2f-c0a8-5656-a919-e51b88b6bc86', 'طرح تلميذٌ فكتب 736 − 248 = 588. كيف نكتشف خطأه بالتحقّق؟', '[{"id":"a","text":"نجمع 588 + 736 ونقارن بـ 248"},{"id":"b","text":"نجمع 588 + 248 فنجد 836 لا 736، فالطرح خاطئ"},{"id":"c","text":"نطرح 588 − 248 ونقارن بـ 736"},{"id":"d","text":"لا يمكن اكتشاف الخطأ"}]'::jsonb, 'b', 'نتحقّق بالعلاقة: الفرق + المطروح = المطروح منه. 588 + 248 = 836، وهو لا يساوي 736، إذن الطرح خاطئ (والصواب 736 − 248 = 488). ✓ الفخّ: الاكتفاء بالطرح دون التحقّق بالجمع.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

