INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6fead7f8-4c19-5592-8432-5a01be38d9f5', 'd907842c-3f08-57fa-986f-20fc4e2bd27d', 'وزّعنا 12 حلوى بالتساوي على 4 أطفال. كم حلوى لكلّ طفل؟', '[{"id":"a","text":"3"},{"id":"b","text":"4"},{"id":"c","text":"8"},{"id":"d","text":"16"}]'::jsonb, 'a', 'نبحث عن عددٍ إذا ضربناه في 4 أعطى 12. من جدول الضرب: 4 × 3 = 12، إذن 12 ÷ 4 = 3 حلوى لكلّ طفل.', 1)
