INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('36643795-8ca2-5fc5-ada2-222aad0e795c', 'd907842c-3f08-57fa-986f-20fc4e2bd27d', 'في العمليّة 18 ÷ 5، ما هو «المقسوم»؟', '[{"id":"a","text":"5"},{"id":"b","text":"3"},{"id":"c","text":"18"},{"id":"d","text":"2"}]'::jsonb, 'c', 'المقسوم هو العدد الذي نقسمه، وهو 18 هنا. أمّا 5 فهو المقسوم عليه (العدد الذي نقسم عليه).', 2)
