INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6347b3d0-3461-5b00-bc3a-9af3218b0147', 'd907842c-3f08-57fa-986f-20fc4e2bd27d', 'أيّ علاقةٍ صحيحةٌ دائمًا في كلّ قسمة؟', '[{"id":"a","text":"المقسوم = المقسوم عليه + الخارج"},{"id":"b","text":"الباقي > المقسوم عليه"},{"id":"c","text":"المقسوم = الخارج − الباقي"},{"id":"d","text":"المقسوم = (المقسوم عليه × الخارج) + الباقي"}]'::jsonb, 'd', 'القانون الأساسيّ للقسمة هو: المقسوم = (المقسوم عليه × الخارج) + الباقي، مع شرط أنّ الباقي < المقسوم عليه دائمًا.', 5)
