INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('718785ab-6797-560a-9478-febf01ab05a3', 'b0439855-fd27-5a52-a51e-5a8be6812168', 'في قسمةٍ المقسوم عليه 5 والخارج 8 والباقي 3. ما المقسوم؟', '[{"id":"a","text":"16"},{"id":"b","text":"40"},{"id":"c","text":"43"},{"id":"d","text":"53"}]'::jsonb, 'c', 'نطبّق القانون: المقسوم = (المقسوم عليه × الخارج) + الباقي = (5 × 8) + 3 = 40 + 3 = 43 ✓. الفخّ: نسيان الباقي يعطي 40 الخاطئ.', 4)
