INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a4fea175-5760-578a-82dc-614c60a37f1f', 'b0439855-fd27-5a52-a51e-5a8be6812168', 'أيّ قسمةٍ من التالية خاطئة؟', '[{"id":"a","text":"23 ÷ 4 خارجها 5 وباقيها 3"},{"id":"b","text":"31 ÷ 6 خارجها 5 وباقيها 1"},{"id":"c","text":"27 ÷ 5 خارجها 5 وباقيها 2"},{"id":"d","text":"19 ÷ 3 خارجها 6 وباقيها 4"}]'::jsonb, 'd', 'في 19 ÷ 3 الباقي 4 أكبر من المقسوم عليه 3، وهذا ممنوع! الصواب: 3 × 6 = 18 والباقي 19 − 18 = 1. أمّا a و b و c فصحيحة بالتحقّق (مثلًا (4 × 5) + 3 = 23 ✓). الفخّ: ترك باقٍ أكبر من المقسوم عليه.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
