  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('18432644-52b2-5398-8f33-da7e42f1659a', 'b0439855-fd27-5a52-a51e-5a8be6812168', 'نضع 50 كتابًا في رفوف، كلّ رفٍّ يسع 6 كتب. كم رفًّا نملأ تمامًا وكم كتابًا يَفضُل؟', '[{"id":"a","text":"7 رفوف ويَفضُل 8 كتب"},{"id":"b","text":"8 رفوف ويَفضُل 2 كتاب"},{"id":"c","text":"9 رفوف ويَفضُل 4 كتب"},{"id":"d","text":"8 رفوف ويَفضُل 6 كتب"}]'::jsonb, 'b', 'نقسم 50 ÷ 6: أكبر مضاعفٍ للعدد 6 لا يتجاوز 50 هو 48 = 6 × 8، فالخارج 8 والباقي 50 − 48 = 2. تحقّق: (6 × 8) + 2 = 50 ✓. إذن 8 رفوف ويَفضُل كتابان. الفخّ: «يَفضُل 6» مرفوض لأنّ الباقي أصغر من 6.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

