INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ad000342-dffb-538d-8e28-8e4950493ab1', '44714b14-fbcf-55d7-bc35-b135756e672f', 'في العمليّة 20 ÷ 4 = 5، ما هو «الخارج»؟', '[{"id":"a","text":"20"},{"id":"b","text":"4"},{"id":"c","text":"5"},{"id":"d","text":"0"}]'::jsonb, 'c', 'الخارج هو نتيجة القسمة، وهو 5 هنا. أمّا 20 فهو المقسوم و 4 المقسوم عليه.', 2)
