INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8b8d1427-4548-50a1-9f70-eaa7533c617e', '44714b14-fbcf-55d7-bc35-b135756e672f', 'ما الخارج والباقي في القسمة 17 ÷ 5؟', '[{"id":"a","text":"الخارج 3 والباقي 2"},{"id":"b","text":"الخارج 2 والباقي 7"},{"id":"c","text":"الخارج 4 والباقي 1"},{"id":"d","text":"الخارج 3 والباقي 0"}]'::jsonb, 'a', 'أكبر مضاعفٍ للعدد 5 لا يتجاوز 17 هو 15 = 5 × 3، فالخارج 3 والباقي 17 − 15 = 2. تحقّق: (5 × 3) + 2 = 17.', 3)
