INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('47acd83e-92fe-5d18-803c-dd40cd14fa16', '44714b14-fbcf-55d7-bc35-b135756e672f', 'وزّعنا 19 تفّاحة بالتساوي على 5 أطفال. كم تفّاحةً لكلّ طفل وكم تَفضُل؟', '[{"id":"a","text":"لكلٍّ 4 وتَفضُل 1"},{"id":"b","text":"لكلٍّ 3 وتَفضُل 5"},{"id":"c","text":"لكلٍّ 3 وتَفضُل 4"},{"id":"d","text":"لكلٍّ 5 وتَفضُل 0"}]'::jsonb, 'c', 'نقسم 19 ÷ 5: أكبر مضاعفٍ للعدد 5 لا يتجاوز 19 هو 15 = 5 × 3، فلكلّ طفلٍ 3 تفّاحات والباقي 19 − 15 = 4. تحقّق: (5 × 3) + 4 = 19، والباقي 4 أصغر من 5.', 6)
