INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('93a9ac5e-ded2-5279-85c9-13aaf85a4f86', '446e1cb5-0aac-50c8-aba4-239812a8c6e0', 'عند القسمة على 6، ما أكبر باقٍ ممكن؟', '[{"id":"a","text":"6"},{"id":"b","text":"7"},{"id":"c","text":"5"},{"id":"d","text":"0"}]'::jsonb, 'c', 'الباقي يجب أن يكون دائمًا أصغر من المقسوم عليه، فعند القسمة على 6 يكون الباقي من 0 إلى 5، وأكبره 5 ✓. الفخّ: اختيار 6 أو 7، وهما يساويان أو يتجاوزان المقسوم عليه.', 1)
