INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5ee5b33a-56d0-54fd-b476-874fbcbc1d93', '446e1cb5-0aac-50c8-aba4-239812a8c6e0', 'وزّع معلّمٌ 62 قلمًا بالتساوي على 4 تلاميذ. كم قلمًا لكلّ تلميذ وكم قلمًا يَفضُل؟', '[{"id":"a","text":"لكلٍّ 15 ويَفضُل 2"},{"id":"b","text":"لكلٍّ 14 ويَفضُل 6"},{"id":"c","text":"لكلٍّ 16 ويَفضُل 2"},{"id":"d","text":"لكلٍّ 15 ويَفضُل 0"}]'::jsonb, 'a', 'نقسم 62 ÷ 4: أكبر مضاعفٍ للعدد 4 لا يتجاوز 62 هو 60 = 4 × 15، فالخارج 15 والباقي 62 − 60 = 2. تحقّق: (4 × 15) + 2 = 62 ✓. الفخّ: «يَفضُل 6» مرفوض لأنّ الباقي على 4 لا يتجاوز 3.', 2)
