INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2556c56c-552f-5379-a526-30b89cf19e12', 'd140277e-7ed3-5cd2-94c9-af5fc2f08dc0', 'ما الخارج والباقي في القسمة 53 ÷ 7؟', '[{"id":"a","text":"الخارج 6 والباقي 11"},{"id":"b","text":"الخارج 7 والباقي 4"},{"id":"c","text":"الخارج 4 والباقي 7"},{"id":"d","text":"الخارج 8 والباقي 3"}]'::jsonb, 'b', 'أكبر مضاعفٍ للعدد 7 لا يتجاوز 53 هو 49 = 7 × 7، فالخارج 7 والباقي 53 − 49 = 4. تحقّق: (7 × 7) + 4 = 53 ✓. الفخّ: «الباقي 11» مرفوض لأنّ الباقي على 7 لا يتجاوز 6.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('25695930-752a-5883-98cf-f644af14aaec', 'd140277e-7ed3-5cd2-94c9-af5fc2f08dc0', 'أيّ قسمةٍ من التالية تامّة (باقيها 0)؟', '[{"id":"a","text":"36 ÷ 6"},{"id":"b","text":"37 ÷ 6"},{"id":"c","text":"40 ÷ 6"},{"id":"d","text":"41 ÷ 6"}]'::jsonb, 'a', 'القسمة التامّة باقيها 0. نجد 36 = 6 × 6 بالضبط، فـ 36 ÷ 6 = 6 والباقي 0 ✓. أمّا 37 فباقيها 1، و 40 باقيها 4، و 41 باقيها 5. الفخّ: ظنّ أنّ كلّ عددٍ قريبٍ من مضاعفٍ تامّ القسمة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b083a141-af18-5f1a-8d1f-63beb5f6cf41', 'd140277e-7ed3-5cd2-94c9-af5fc2f08dc0', 'وزّعنا 45 بطاقةً بالتساوي على 4 لاعبين. كم بطاقةً لكلّ لاعبٍ وكم تَفضُل؟', '[{"id":"a","text":"لكلٍّ 10 وتَفضُل 5"},{"id":"b","text":"لكلٍّ 12 وتَفضُل 1"},{"id":"c","text":"لكلٍّ 11 وتَفضُل 1"},{"id":"d","text":"لكلٍّ 11 وتَفضُل 0"}]'::jsonb, 'c', 'نقسم 45 ÷ 4: أكبر مضاعفٍ للعدد 4 لا يتجاوز 45 هو 44 = 4 × 11، فلكلّ لاعبٍ 11 بطاقة والباقي 45 − 44 = 1. تحقّق: (4 × 11) + 1 = 45 ✓. الفخّ: «تَفضُل 5» مرفوض لأنّ الباقي على 4 لا يتجاوز 3.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

