INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a1af2130-777b-518d-bb88-b899a16ef30d', '96323294-48fc-5e7f-bcef-b0365131a18d', 'اشترت فتاةٌ دفترًا بـ 850 م ودفعت 1 د (= 1 000 م). كم باقيها؟', '[{"id":"a","text":"250 م"},{"id":"b","text":"150 م"},{"id":"c","text":"850 م"},{"id":"d","text":"1 850 م"}]'::jsonb, 'b', 'نحوّل الدينار: 1 د = 1 000 م، ثمّ الباقي = 1 000 − 850 = 150 م. ✓ الفخّ: طرح 850 من 100 بدل 1 000.', 3)
