INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('84d3d989-f19c-5c48-8cf8-96256dc4a75d', '773a5ee3-6841-5a8d-981c-6ddf6cfea35e', 'ما اسم جزء المستقيم المحصور بين نقطتين A و B، والذي يمكن قياس طوله؟', '[{"id":"a","text":"المستقيم"},{"id":"b","text":"نصف المستقيم"},{"id":"c","text":"القطعة المستقيمة [AB]"},{"id":"d","text":"النقطة"}]'::jsonb, 'c', 'الجزء المحصور بين نقطتين هو القطعة المستقيمة [AB]؛ لها بدايةٌ ونهاية ويمكن قياس طولها، بخلاف المستقيم الذي يمتدّ بلا نهاية.', 1)
