INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e21910aa-f82d-53d8-b518-90c5763d3191', '773a5ee3-6841-5a8d-981c-6ddf6cfea35e', 'مستطيلٌ طوله 9 cm وعرضه 4 cm. ما محيطه؟', '[{"id":"a","text":"13 cm"},{"id":"b","text":"26 cm"},{"id":"c","text":"36 cm"},{"id":"d","text":"18 cm"}]'::jsonb, 'b', 'محيط المستطيل = 2 × (الطول + العرض) = 2 × (9 + 4) = 2 × 13 = 26 cm. الفخّ: 9 + 4 = 13 هو نصف المحيط فقط، ويجب ضربه في 2.', 5)
