INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9b3a0b0a-b96d-5153-8f2a-9367122d7098', 'cd0efbc2-167c-5a79-a812-58453452fce0', 'مستطيلٌ طوله 20 cm وعرضه 5 cm. ما محيطه؟', '[{"id":"a","text":"25 cm"},{"id":"b","text":"100 cm"},{"id":"c","text":"50 cm"},{"id":"d","text":"40 cm"}]'::jsonb, 'c', 'محيط المستطيل = 2 × (20 + 5) = 2 × 25 = 50 cm. ✓ الفخّ: 25 هو الطول + العرض فقط (نصف المحيط)، و 100 هو 20 × 5 (طول × عرض).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('71c2204f-1497-5e83-a9bc-4562cc8d2212', 'cd0efbc2-167c-5a79-a812-58453452fce0', 'محيط مثلّثٍ يساوي 30 cm، وطولا ضلعين منه 11 cm و 9 cm. ما طول الضلع الثالث؟', '[{"id":"a","text":"10 cm"},{"id":"b","text":"20 cm"},{"id":"c","text":"50 cm"},{"id":"d","text":"8 cm"}]'::jsonb, 'a', 'الضلع الثالث = المحيط − مجموع الضلعين = 30 − (11 + 9) = 30 − 20 = 10 cm. ✓ الفخّ: 20 هو مجموع الضلعين فقط، و 50 هو جمع المحيط مع الضلعين بدل طرحهما.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

